class Solution {
    public long smallestNumber(long num) {
        char[] chars = String.valueOf(Math.abs(num)).toCharArray();
        Arrays.sort(chars);
        if (num < 0) {
            for (int i = 1; i < chars.length; i++) {
                if (chars[i] != '0') {
                    char temp = chars[0];
                    chars[0] = chars[i];
                    chars[i] = temp;
                    break;
                }
            }
        } else if (chars[0] == '0') {
            for (int i = 1; i < chars.length; i++) {
                if (chars[i] != '0') {
                    char temp = chars[0];
                    chars[0] = chars[i];
                    chars[i] = temp;
                    break;
                }
            }
        }
        return num < 0 ? -Long.parseLong(new String(chars)) : Long.parseLong(new String(chars));
    }
}
